/* Structure Syntax */
struct TagName {
    dataType member1;
    dataType member2;
} instance1, instance2;

/* Typedef with Structure */
typedef struct {
    dataType member1;
    dataType member2;
} TypeAlias;

/* Union Syntax */
union UnionTag {
    dataType member1;
    dataType member2;
} unionInstance;

/* Accessing Members */
instance1.member1 = value;   /* Dot operator for direct variables */
TypeAlias *ptr = &instance1;
ptr->member1 = value;        /* Arrow operator for pointers */

