#include <stdio.h>
#include <string.h>

/* Sub-structure for tracking addresses */
typedef struct {
    char city[50];
    int zipCode;
} Address;

/* Main user structure */
typedef struct {
    char name[30];
    int id;
    double salary;
    Address addr; /* Nested Structure */
} Employee;

/* Function prototype using read-only const pointer */
void printEmployee(const Employee *emp);
void giveRaise(Employee *emp, double bonus);

int main(void) {
    /* Initialization of nested structure */
    Employee emp1 = {
        "Alice Vance",
        1023,
        75000.00,
        {"New York", 10001}
    };

    printf("--- Initial Profile ---\n");
    printEmployee(&emp1);

    /* Pass by pointer to modify value */
    giveRaise(&emp1, 5250.50);

    printf("\n--- Updated Profile ---\n");
    printEmployee(&emp1);

    /* Demonstrating sizing and alignment padding */
    printf("\n--- Size Information ---\n");
    printf("Size of Address struct: %zu bytes\n", sizeof(Address));
    printf("Size of Employee struct: %zu bytes\n", sizeof(Employee));

    return 0;
}

void printEmployee(const Employee *emp) {
    /* Accessing members using arrow (->) and nested dots (.) */
    printf("Name   : %s\n", emp->name);
    printf("ID     : %d\n", emp->id);
    printf("Salary : $%.2f\n", emp->salary);
    printf("City   : %s\n", emp->addr.city);
    printf("ZIP    : %d\n", emp->addr.zipCode);
}

void giveRaise(Employee *emp, double bonus) {
    if (emp != NULL) {
        emp->salary += bonus; /* Modifies caller's data directly */
    }
}

