#include <stdio.h>

/* A union representing an IPv4 Address */
union IPAddress {
    unsigned int fullAddress; /* 4 bytes */
    unsigned char octets[4];  /* 4 bytes (1 byte each) */
};

int main(void) {
    union IPAddress myIP;

    /* Initialize using the full raw 32-bit unsigned integer */
    myIP.fullAddress = 0x0100007F; /* Hex representation of localhost 127.0.0.1 in little-endian order */

    printf("--- Union Memory Share Demonstration ---\n");
    printf("Full 32-bit value (hex) : 0x%08X\n", myIP.fullAddress);

    /* Access individual bytes of the integer directly using octets array */
    printf("Octet 0: %d\n", myIP.octets[0]);
    printf("Octet 1: %d\n", myIP.octets[1]);
    printf("Octet 2: %d\n", myIP.octets[2]);
    printf("Octet 3: %d\n", myIP.octets[3]);

    /* Overwrite just one octet and see changes globally */
    myIP.octets[0] = 192;
    myIP.octets[1] = 168;
    myIP.octets[2] = 1;
    myIP.octets[3] = 50;

    printf("\nAfter modifying individual octets:\n");
    printf("Full 32-bit integer (hex): 0x%08X\n", myIP.fullAddress);
    printf("Size of entire union      : %zu bytes\n", sizeof(myIP));

    return 0;
}

