typedef struct {
    char name[50];
    double grade;
} Student;

double getAverageGrade(const Student students[], int size) {
    if (size <= 0) return 0.0;
    double sum = 0.0;
    for (int i = 0; i < size; i++) {
        sum += students[i].grade;
    }
    return sum / size;
}
```

