typedef struct {
    int id;
    double value;
} DataNode;

void swapNodes(DataNode *a, DataNode *b) {
    if (a != NULL && b != NULL) {
        DataNode temp = *a;  /* Entire structure copy */
        *a = *b;
        *b = temp;
    }
}
```

