#include <stdio.h>
#include <math.h>

typedef struct {
    double x;
    double y;
    double z;
} Point3D;

double calculateDistance(const Point3D *p1, const Point3D *p2) {
    double dx = p1->x - p2->x;
    double dy = p1->y - p2->y;
    double dz = p1->z - p2->z;
    return sqrt(dx*dx + dy*dy + dz*dz);
}
```

